function solve(m: number, n: number, waitCost: number[][]): number {
    // Directions: right (0, 1), down (1, 0)
    const directions = [[0, 1], [1, 0]];

    // Priority queue: [total_cost, i, j, step]
    const heap: [number, number, number, number][] = [];
    heap.push([(0 + 1) * (0 + 1), 0, 0, 1]);

    // Visited map to keep track of minimal cost for (i, j, step % 2)
    const visited = new Map<string, number>();
    visited.set(`${0},${0},${1 % 2}`, (0 + 1) * (0 + 1));

    while (heap.length > 0) {
        heap.sort((a, b) => a[0] - b[0]);
        const [current_cost, i, j, step] = heap.shift()!;

        if (i === m - 1 && j === n - 1) {
            return current_cost;
        }

        if (step % 2 === 1) {  // Odd step: move
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;
                if (0 <= ni && ni < m && 0 <= nj && nj < n) {
                    const new_cost = current_cost + (ni + 1) * (nj + 1);
                    const new_step = step + 1;
                    const key = `${ni},${nj},${new_step % 2}`;
                    if (!visited.has(key) || new_cost < visited.get(key)!) {
                        visited.set(key, new_cost);
                        heap.push([new_cost, ni, nj, new_step]);
                    }
                }
            }
        } else {  // Even step: wait
            const new_cost = current_cost + waitCost[i][j];
            const new_step = step + 1;
            const key = `${i},${j},${new_step % 2}`;
            if (!visited.has(key) || new_cost < visited.get(key)!) {
                visited.set(key, new_cost);
                heap.push([new_cost, i, j, new_step]);
            }
        }
    }

    return -1;  // Should not reach here for valid inputs
}
